async function fetchGraphQLBet(t,e){const o=extractAuthDataFromCookie();if(!o)throw new Error("Unable to retrieve authorization data.");return(await fetch(API_URL,{method:"POST",headers:{"Content-Type":"application/json",Authorization:`Bearer ${o.accessToken}`},body:JSON.stringify({query:t,variables:e})})).json()}function calculateTimeInterval(){const t=new Date,e=new Date(t);e.setHours(t.getHours()<12?0:12,0,0,0);const o=new Date(e);return o.setHours(e.getHours()+12),{from:e.toISOString(),to:o.toISOString()}}async function showBetProgress(){const t=calculateTimeInterval(),e=extractAuthDataFromCookie();if(!e)return void alert("Authorization data is missing.");try{const o=await fetchGraphQLBet("\n        query GameSessionStats($userId: ID!, $createdAtFrom: DateTime, $createdAtTo: DateTime) {\n            gameSessionStats(userId: $userId, createdAtFrom: $createdAtFrom, createdAtTo: $createdAtTo) {\n                totalBet\n            }\n        }\n    ",{userId:e.userId,createdAtFrom:t.from,createdAtTo:t.to});displayProgressBars(o.data?.gameSessionStats?.[0]?.totalBet||0)}catch(t){alert("Failed to fetch progress data.")}}function displayProgressBars(t){const e=document.getElementById("progressBarContainer"),o=document.getElementById("progressStage1"),r=document.getElementById("progressStage2"),a=document.getElementById("progressStage3"),n=document.getElementById("progressInfo");if(!(e&&o&&r&&a&&n))return;e.style.display="flex",n.style.display="block",n.textContent=`${t}₾`;const s=Math.min(t/6e3*100,100),i=t>6e3?Math.min((t-6e3)/9e3*100,100):0,c=t>15e3?Math.min((t-15e3)/15e3*100,100):0;o.style.width=`${s}%`,o.textContent=`${s.toFixed(2)}%`,r.style.width=`${i}%`,r.textContent=`${i.toFixed(2)}%`,a.style.width=`${c}%`,a.textContent=`${c.toFixed(2)}%`}